<?php
// deploy_images.php
$images = {
    "images/logo.png": "",
    "images/main_visual.jpg": ""
};
foreach ($images as $name => $b64) {
    $path = __DIR__ . '/' . $name;
    $dir = dirname($path);
    if (!is_dir($dir)) mkdir($dir, 0755, true);
    file_put_contents($path, base64_decode($b64));
    echo "Uploaded: $name<br>";
}
?>